rust.code:
impl Solution {
    pub fn find_words_containing(words: Vec<String>, x: char) -> Vec<i32> {
        words
            .into_iter()
            .enumerate()
            .filter_map(|(i, w)| w.contains(x).then(|| i as i32))
            .collect()
    }
}
